            title="Total Vehicles"
            value={vehicles.length}
            icon={Bus}
            iconColor="text-blue-500"
          />
          <StatsCard
            title="Total Drivers"
            value={drivers.length}
            icon={Users}
            iconColor="text-green-500"
          />
          <StatsCard
            title="Students Using Transport"
            value={allocations.length}
            icon={UserCheck}
            iconColor="text-purple-500"
