  studentName: string;
  roomNumber: string;
  month: string;
  year: number;
  rentAmount: number;
  messAmount: number;
  utilitiesAmount: number;
  otherCharges: number;
  totalAmount: number;
  paidAmount: number;
  dueDate: string;
  status: "Pending" | "Paid" | "Partial" | "Overdue";
  paymentDate?: string;
  paymentMethod?: string;
  remarks?: string;
  createdAt: Date;
  updatedAt: Date;
}

const HostelFeeSchema = new Schema<IHostelFee>(
  {
    feeId: { type: String, required: true, unique: true },
    residentId: { type: String, required: true },
    studentId: { type: String, required: true },
    studentName: { type: String, required: true },
    roomNumber: { type: String, required: true },
    month: { type: String, required: true },
    year: { type: Number, required: true },
    rentAmount: { type: Number, required: true },
    messAmount: { type: Number, default: 0 },
    utilitiesAmount: { type: Number, default: 0 },
    otherCharges: { type: Number, default: 0 },
    totalAmount: { type: Number, required: true },
    paidAmount: { type: Number, default: 0 },
    dueDate: { type: String, required: true },
    status: { type: String, enum: ["Pending", "Paid", "Partial", "Overdue"], default: "Pending" },
    paymentDate: { type: String },
    paymentMethod: { type: String },
    remarks: { type: String },
  },
  { timestamps: true }
);

export default mongoose.model<IHostelFee>("HostelFee", HostelFeeSchema);

client/src/pages/attendance/mark-staff.t.content:
import { useState, useEffect, useMemo } from "react";
import { format } from "date-fns";
import { ModuleLayout } from "@/components/layout/module-layout";
import {
  attendanceNavItems,
  useStaffForAttendance,
  useAttendanceData,
  useMarkAttendance,
} from "./attendance-data";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { useToast } from "@/hooks/use-toast";
import { CheckCircle, XCircle, Loader2, Info } from "lucide-react";

type StatusMap = Record<string, "PRESENT" | "ABSENT" | "LEAVE">;

export default function MarkStaff() {
  const [selectedDate, setSelectedDate] = useState(format(new Date(), "yyyy-MM-dd"));
  const [statusMap, setStatusMap] = useState<StatusMap>({});
  const [hasLocalChanges, setHasLocalChanges] = useState(false);
  const { toast } = useToast();

  const { data: allStaff = [], isLoading: staffLoading } = useStaffForAttendance();
  const { records: existingRecords, isLoading: recordsLoading } = useAttendanceData({
    date: selectedDate,
    targetType: "STAFF",
  });
  const markMutation = useMarkAttendance();

  const activeStaff = allStaff.filter((s) => s.status === "Active");

  const markedStaffIds = useMemo(() => {
    const set = new Set<string>();
    existingRecords.forEach((r) => {
      if (r.staffId) set.add(r.staffId);
    });
    return set;
  }, [existingRecords]);

  const markedCount = activeStaff.filter((s) => markedStaffIds.has(s.staffId)).length;
  const allMarked = activeStaff.length > 0 && markedCount === activeStaff.length;
  const partiallyMarked = markedCount > 0 && markedCount < activeStaff.length;

  const staffIdKey = useMemo(() => activeStaff.map((s) => s.staffId).join(","), [activeStaff]);
  const recordIdKey = useMemo(() => existingRecords.map((r) => r.id).join(","), [existingRecords]);

  useEffect(() => {
    const newStatusMap: StatusMap = {};
    activeStaff.forEach((staff) => {
      const existing = existingRecords.find(
        (r) => r.staffId === staff.staffId && r.date === selectedDate
      );
      newStatusMap[staff.staffId] = existing ? existing.status as "PRESENT" | "ABSENT" | "LEAVE" : "PRESENT";
    });
    setStatusMap(newStatusMap);
    setHasLocalChanges(false);
  }, [staffIdKey, recordIdKey, selectedDate]);

  const handleStatusChange = (staffId: string, status: "PRESENT" | "ABSENT" | "LEAVE") => {
    setStatusMap((prev) => ({ ...prev, [staffId]: status }));
    setHasLocalChanges(true);
  };

  const handleMarkAll = (status: "PRESENT" | "ABSENT") => {
    const newMap: StatusMap = {};
    activeStaff.forEach((s) => {
      newMap[s.staffId] = status;
    });
    setStatusMap(newMap);
    setHasLocalChanges(true);
  };

  const handleSubmit = async () => {
    if (activeStaff.length === 0) {
      toast({ title: "No staff", description: "No active staff found.", variant: "destructive" });
      return;
    }

    const records = activeStaff.map((staff) => ({
      date: selectedDate,
      targetType: "STAFF" as const,
      staffId: staff.staffId,
      entityName: staff.name,
      status: statusMap[staff.staffId] || "PRESENT",
    }));

    try {
      await markMutation.mutateAsync(records);
      setHasLocalChanges(false);
      toast({
        title: allMarked ? "Attendance updated" : "Attendance saved",
        description: `Attendance ${allMarked ? "updated" : "saved"} for ${records.length} staff members.`,
      });
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : "Failed to mark attendance";
      toast({ title: "Error", description: message, variant: "destructive" });
    }
  };

  return (
    <ModuleLayout module="attendance" navItems={attendanceNavItems}>
      <div className="space-y-6">
        <div>
          <h1 className="text-2xl lg:text-3xl font-semibold" data-testid="text-page-title">
            Mark Staff Attendance
          </h1>
          <p className="text-muted-foreground mt-1">Mark daily attendance for staff members</p>
        </div>

        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-lg">Select Date</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex flex-wrap items-end gap-4">
              <div className="space-y-1">
                <label className="text-sm font-medium text-muted-foreground">Date</label>
                <Input
                  type="date"
                  value={selectedDate}
                  onChange={(e) => setSelectedDate(e.target.value)}
                  data-testid="input-date"
                />
              </div>
            </div>
          </CardContent>
        </Card>

        {recordsLoading ? (
          <div className="flex items-center justify-center gap-2 py-4">
            <Loader2 className="w-4 h-4 animate-spin" />
            <span className="text-sm text-muted-foreground">Checking existing records...</span>
          </div>
        ) : allMarked ? (
          <div className="flex items-center gap-3 rounded-md border border-green-200 dark:border-green-900 bg-green-50 dark:bg-green-950/30 px-4 py-3" data-testid="banner-already-marked">
            <CheckCircle className="w-5 h-5 text-green-600 dark:text-green-400 shrink-0" />
            <div className="flex-1">
              <p className="text-sm font-medium text-green-800 dark:text-green-300">
                Attendance already marked for {selectedDate}
              </p>
              <p className="text-xs text-green-600 dark:text-green-500">
                All {markedCount} staff marked. You can change any status below and click "Update Attendance" to save.
              </p>
            </div>
          </div>
        ) : partiallyMarked ? (
          <div className="flex items-center gap-3 rounded-md border border-orange-200 dark:border-orange-900 bg-orange-50 dark:bg-orange-950/30 px-4 py-3" data-testid="banner-partially-marked">
            <Info className="w-5 h-5 text-orange-600 dark:text-orange-400 shrink-0" />
            <div className="flex-1">
              <p className="text-sm font-medium text-orange-800 dark:text-orange-300">
                Partially marked for {selectedDate}
              </p>
              <p className="text-xs text-orange-600 dark:text-orange-500">
                {markedCount} of {activeStaff.length} staff marked. Click "Save Attendance" to save all.
              </p>
            </div>
          </div>
        ) : (
          <div className="flex items-center gap-3 rounded-md border px-4 py-3" data-testid="banner-not-marked">
            <Info className="w-5 h-5 text-muted-foreground shrink-0" />
            <p className="text-sm text-muted-foreground">
              No attendance recorded yet for {selectedDate}. Select status for each staff member and click "Save Attendance".
            </p>
          </div>
        )}

        <Card>
          <CardHeader className="pb-3">
            <div className="flex flex-wrap items-center justify-between gap-4">
              <CardTitle className="text-lg">
                Staff Members ({activeStaff.length})
              </CardTitle>
              <div className="flex flex-wrap gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleMarkAll("PRESENT")}
                  data-testid="button-mark-all-present"
                >
                  <CheckCircle className="w-4 h-4 mr-1" />
                  Mark All Present
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleMarkAll("ABSENT")}
                  data-testid="button-mark-all-absent"
                >
                  <XCircle className="w-4 h-4 mr-1" />
                  Mark All Absent
                </Button>
              </div>
            </div>
          </CardHeader>
          <CardContent>
            {staffLoading ? (
              <div className="flex items-center justify-center gap-2 py-8">
                <Loader2 className="w-5 h-5 animate-spin" />
                <span className="text-muted-foreground">Loading staff...</span>
              </div>
            ) : activeStaff.length === 0 ? (
              <p className="text-muted-foreground text-center py-8">
                No active staff members found
              </p>
            ) : (
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="text-xs uppercase tracking-wide">Staff ID</TableHead>
                      <TableHead className="text-xs uppercase tracking-wide">Name</TableHead>
                      <TableHead className="text-xs uppercase tracking-wide">Department</TableHead>
                      <TableHead className="text-xs uppercase tracking-wide">Designation</TableHead>
                      <TableHead className="text-xs uppercase tracking-wide">Status</TableHead>
                      <TableHead className="text-xs uppercase tracking-wide w-[100px]">Saved</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {activeStaff.map((staff) => {
                      const isSaved = markedStaffIds.has(staff.staffId);
                      return (
                        <TableRow key={staff.staffId}>
                          <TableCell className="text-sm" data-testid={`text-staff-id-${staff.staffId}`}>
                            {staff.staffId}
                          </TableCell>
                          <TableCell className="text-sm" data-testid={`text-staff-name-${staff.staffId}`}>
                            {staff.name}
                          </TableCell>
                          <TableCell className="text-sm">{staff.department}</TableCell>
                          <TableCell className="text-sm">{staff.designation}</TableCell>
                          <TableCell>
                            <Select
                              value={statusMap[staff.staffId] || "PRESENT"}
                              onValueChange={(val) => handleStatusChange(staff.staffId, val as "PRESENT" | "ABSENT" | "LEAVE")}
                            >
                              <SelectTrigger className="w-[130px]" data-testid={`select-status-${staff.staffId}`}>
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="PRESENT">PRESENT</SelectItem>
                                <SelectItem value="ABSENT">ABSENT</SelectItem>
                                <SelectItem value="LEAVE">LEAVE</SelectItem>
                              </SelectContent>
                            </Select>
                          </TableCell>
                          <TableCell>
                            {isSaved ? (
                              <Badge variant="secondary" className="text-xs" data-testid={`badge-saved-${staff.staffId}`}>
                                Saved
                              </Badge>
                            ) : (
                              <span className="text-xs text-muted-foreground">Not saved</span>
                            )}
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </Table>
              </div>
            )}

            {activeStaff.length > 0 && (
              <div className="flex flex-wrap items-center justify-between gap-4 mt-4">
                {hasLocalChanges && (
                  <p className="text-sm text-orange-600 dark:text-orange-400">You have unsaved changes</p>
                )}
                <div className="ml-auto">
                  <Button
                    onClick={handleSubmit}
                    disabled={markMutation.isPending}
                    data-testid="button-submit-attendance"
                  >
                    {markMutation.isPending && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                    {allMarked ? "Update Attendance" : "Save Attendance"}
                  </Button>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </ModuleLayout>
  );
}

client/src/pages/fee/payments.tsx.content:
import { useState } from "react";
import { ModuleLayout } from "@/components/layout/module-layout";
import { PageHeader } from "@/components/shared/page-header";
import { feeNavItems, useChallans, usePayments } from "./fee-data";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Plus, Eye, Search, Filter, Receipt, CreditCard, Wallet, Banknote } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { Badge } from "@/components/ui/badge";
import { useQuery } from "@tanstack/react-query";
import { type Student, type Payment, type InsertPayment } from "@shared/schema";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

const paymentModes = ["Cash", "Bank Transfer", "Cheque", "Online", "Card"] as const;

export default function FeePayments() {
  const { payments, createPayment, isPending } = usePayments();
  const { challans } = useChallans();
  const { data: students = [] } = useQuery<Student[]>({ queryKey: ["/api/students"] });
  const { toast } = useToast();

  const [dialogOpen, setDialogOpen] = useState(false);
  const [viewDialogOpen, setViewDialogOpen] = useState(false);
  const [selectedPayment, setSelectedPayment] = useState<Payment | null>(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [typeFilter, setTypeFilter] = useState<string>("all");

  const [formData, setFormData] = useState({
    challanId: "",
    amount: 0,
    paymentMode: "Cash" as typeof paymentModes[number],
    transactionRef: "",
    notes: "",
    type: "Payment" as "Payment" | "Refund" | "Adjustment",
  });

  const pendingChallans = challans.filter(c => c.status !== "Paid" && c.status !== "Cancelled");
  const selectedChallan = challans.find(c => c.id === formData.challanId);

  const handleCreatePayment = async () => {
    if (!formData.challanId || formData.amount <= 0) {
      toast({ title: "Error", description: "Please fill all required fields", variant: "destructive" });
      return;
    }

    if (selectedChallan && formData.type === "Payment" && formData.amount > selectedChallan.balanceAmount) {
      toast({ 
        title: "Error", 
        description: `Payment amount cannot exceed balance of Rs. ${selectedChallan.balanceAmount.toLocaleString()}`, 
        variant: "destructive" 
      });
      return;
    }

    try {
      const payment: InsertPayment = {
        challanId: formData.challanId,
        challanNo: selectedChallan?.challanNo || "",
        studentId: selectedChallan?.studentId || "",
        studentName: selectedChallan?.studentName || "",
        amount: formData.amount,
        paymentDate: new Date().toISOString().split("T")[0],
        paymentMode: formData.paymentMode,
        type: formData.type,
        transactionRef: formData.transactionRef || undefined,
        notes: formData.notes || undefined,
        receivedBy: "System",
        status: "Completed",
      };

      await createPayment(payment);
      toast({ title: "Success", description: `${formData.type} recorded successfully` });
      setDialogOpen(false);
      setFormData({
        challanId: "",
        amount: 0,
        paymentMode: "Cash",
        transactionRef: "",
        notes: "",
        type: "Payment",
      });
    } catch (error) {
      toast({ title: "Error", description: String(error), variant: "destructive" });
    }
  };

  const handleViewPayment = (payment: Payment) => {
    setSelectedPayment(payment);
    setViewDialogOpen(true);
  };

  const getTypeBadge = (type: string) => {
    const variants: Record<string, "default" | "secondary" | "destructive" | "outline"> = {
      "Payment": "default",
      "Refund": "destructive",
      "Adjustment": "outline",
    };
    return <Badge variant={variants[type] || "secondary"}>{type}</Badge>;
  };

  const getMethodIcon = (method: string) => {
    switch (method) {
      case "Cash": return <Banknote className="w-4 h-4" />;
      case "Card": return <CreditCard className="w-4 h-4" />;
      case "Bank Transfer": return <Wallet className="w-4 h-4" />;
      default: return <Receipt className="w-4 h-4" />;
    }
  };

  const filteredPayments = payments.filter(payment => {
    const matchesSearch = payment.receiptNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
      payment.challanNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
      payment.studentName.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = typeFilter === "all" || payment.type === typeFilter;
    return matchesSearch && matchesType;
  });

  const totalCollected = payments
    .filter(p => p.type === "Payment")
    .reduce((sum, p) => sum + p.amount, 0);

  const totalRefunds = payments
    .filter(p => p.type === "Refund")
    .reduce((sum, p) => sum + p.amount, 0);

  return (
    <ModuleLayout module="fee" navItems={feeNavItems}>
      <PageHeader
        title="Payment Collection"
        description="Record and manage fee payments, refunds, and adjustments"
      />

      <div className="grid gap-4 md:grid-cols-3 mb-6">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
            <CardTitle className="text-sm font-medium">Total Collected</CardTitle>
            <Banknote className="w-4 h-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">Rs. {totalCollected.toLocaleString()}</div>
            <p className="text-xs text-muted-foreground">{payments.filter(p => p.type === "Payment").length} payments</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
            <CardTitle className="text-sm font-medium">Total Refunds</CardTitle>
            <Receipt className="w-4 h-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-red-600">Rs. {totalRefunds.toLocaleString()}</div>
            <p className="text-xs text-muted-foreground">{payments.filter(p => p.type === "Refund").length} refunds</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
            <CardTitle className="text-sm font-medium">Net Collection</CardTitle>
            <CreditCard className="w-4 h-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">Rs. {(totalCollected - totalRefunds).toLocaleString()}</div>
            <p className="text-xs text-muted-foreground">After refunds</p>
          </CardContent>
        </Card>
      </div>

      <div className="space-y-4">
        <div className="flex flex-wrap gap-4 items-center justify-between">
          <div className="flex gap-2 items-center">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
              <Input
                placeholder="Search by receipt number..."
                className="pl-10 w-64"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                data-testid="input-search-payment"
              />
            </div>
            <Select value={typeFilter} onValueChange={setTypeFilter}>
              <SelectTrigger className="w-36" data-testid="select-type-filter">
                <Filter className="w-4 h-4 mr-2" />
                <SelectValue placeholder="Type" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Types</SelectItem>
                <SelectItem value="Payment">Payment</SelectItem>
                <SelectItem value="Refund">Refund</SelectItem>
                <SelectItem value="Adjustment">Adjustment</SelectItem>
              </SelectContent>
            </Select>
          </div>
          <Button onClick={() => setDialogOpen(true)} data-testid="button-record-payment">
            <Plus className="w-4 h-4 mr-2" />
            Record Payment
          </Button>
        </div>

        <Card>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Receipt #</TableHead>
                <TableHead>Challan #</TableHead>
                <TableHead>Student</TableHead>
                <TableHead>Date</TableHead>
                <TableHead>Amount</TableHead>
                <TableHead>Method</TableHead>
                <TableHead>Type</TableHead>
                <TableHead>Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredPayments.map((payment) => (
                <TableRow key={payment.id} data-testid={`row-payment-${payment.id}`}>
                  <TableCell className="font-medium">{payment.receiptNo}</TableCell>
                  <TableCell>{payment.challanNo}</TableCell>
                  <TableCell>{payment.studentName}</TableCell>
                  <TableCell>{payment.paymentDate}</TableCell>
                  <TableCell className={payment.type === "Refund" ? "text-red-600" : ""}>
                    {payment.type === "Refund" ? "-" : ""}Rs. {payment.amount.toLocaleString()}
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-1">
                      {getMethodIcon(payment.paymentMode)}
                      <span>{payment.paymentMode}</span>
                    </div>
                  </TableCell>
                  <TableCell>{getTypeBadge(payment.type)}</TableCell>
                  <TableCell>
                    <Button size="sm" variant="ghost" onClick={() => handleViewPayment(payment)} data-testid={`button-view-payment-${payment.id}`}>
                      <Eye className="w-4 h-4" />
                    </Button>
                  </TableCell>
                </TableRow>
              ))}
              {filteredPayments.length === 0 && (
                <TableRow>
                  <TableCell colSpan={8} className="text-center py-8 text-muted-foreground">
                    No payments found. Click "Record Payment" to add one.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </Card>
      </div>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Record Payment</DialogTitle>
            <DialogDescription>Record a payment, refund, or adjustment against a challan</DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label>Transaction Type</Label>
              <Select 
                value={formData.type} 
                onValueChange={(v: "Payment" | "Refund" | "Adjustment") => setFormData(prev => ({ ...prev, type: v }))}
              >
                <SelectTrigger data-testid="select-payment-type">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Payment">Payment</SelectItem>
                  <SelectItem value="Refund">Refund</SelectItem>
                  <SelectItem value="Adjustment">Adjustment</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Select Challan</Label>
              <Select value={formData.challanId} onValueChange={(v) => setFormData(prev => ({ ...prev, challanId: v }))}>
                <SelectTrigger data-testid="select-challan">
                  <SelectValue placeholder="Select a pending challan" />
                </SelectTrigger>
                <SelectContent>
                  {pendingChallans.map((challan) => (
                    <SelectItem key={challan.id} value={challan.id}>
                      {challan.challanNo} - {challan.studentName} (Balance: Rs. {challan.balanceAmount.toLocaleString()})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {selectedChallan && (
              <Card className="bg-muted/50">
                <CardContent className="py-3 text-sm space-y-1">
                  <div className="flex justify-between">
                    <span>Net Amount:</span>
                    <span>Rs. {selectedChallan.netAmount.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Already Paid:</span>
                    <span>Rs. {selectedChallan.paidAmount.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between font-semibold text-primary">
                    <span>Balance Due:</span>
                    <span>Rs. {selectedChallan.balanceAmount.toLocaleString()}</span>
                  </div>
                </CardContent>
              </Card>
            )}

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Amount</Label>
                <Input
                  type="number"
                  placeholder="Enter amount"
                  value={formData.amount || ""}
                  onChange={(e) => setFormData(prev => ({ ...prev, amount: Number(e.target.value) }))}
                  data-testid="input-payment-amount"
                />
              </div>
              <div className="space-y-2">
                <Label>Payment Mode</Label>
                <Select 
                  value={formData.paymentMode} 
                  onValueChange={(v: typeof paymentModes[number]) => setFormData(prev => ({ ...prev, paymentMode: v }))}
                >
                  <SelectTrigger data-testid="select-payment-mode">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {paymentModes.map((mode) => (
                      <SelectItem key={mode} value={mode}>{mode}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-2">
              <Label>Transaction Reference (Optional)</Label>
              <Input
                placeholder="Transaction/Cheque number"
                value={formData.transactionRef}
                onChange={(e) => setFormData(prev => ({ ...prev, transactionRef: e.target.value }))}
                data-testid="input-transaction-ref"
              />
            </div>

            <div className="space-y-2">
              <Label>Notes (Optional)</Label>
              <Input
                placeholder="Any additional notes..."
                value={formData.notes}
                onChange={(e) => setFormData(prev => ({ ...prev, notes: e.target.value }))}
                data-testid="input-payment-notes"
              />
            </div>

            <div className="flex justify-end gap-2">
              <Button variant="outline" onClick={() => setDialogOpen(false)}>Cancel</Button>
              <Button onClick={handleCreatePayment} disabled={isPending} data-testid="button-submit-payment">
                {isPending ? "Processing..." : `Record ${formData.type}`}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={viewDialogOpen} onOpenChange={setViewDialogOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Payment Receipt</DialogTitle>
            <DialogDescription>Receipt #{selectedPayment?.receiptNo}</DialogDescription>
          </DialogHeader>
          {selectedPayment && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div>
                  <span className="text-muted-foreground">Challan No:</span>
                  <p className="font-medium">{selectedPayment.challanNo}</p>
                </div>
                <div>
                  <span className="text-muted-foreground">Student:</span>
                  <p className="font-medium">{selectedPayment.studentName}</p>
                </div>
                <div>
                  <span className="text-muted-foreground">Date:</span>
                  <p className="font-medium">{selectedPayment.paymentDate}</p>
                </div>
                <div>
                  <span className="text-muted-foreground">Mode:</span>
                  <p className="font-medium">{selectedPayment.paymentMode}</p>
                </div>
              </div>

              <Card>
                <CardContent className="py-4 text-center">
                  <div className="text-3xl font-bold">
                    {selectedPayment.type === "Refund" ? "-" : ""}Rs. {selectedPayment.amount.toLocaleString()}
                  </div>
                  <div className="mt-2">{getTypeBadge(selectedPayment.type)}</div>
                </CardContent>
              </Card>

              {selectedPayment.transactionRef && (
                <div className="text-sm">
                  <span className="text-muted-foreground">Reference: </span>
                  <span className="font-medium">{selectedPayment.transactionRef}</span>
                </div>
              )}

              {selectedPayment.notes && (
                <div className="text-sm">
                  <span className="text-muted-foreground">Notes: </span>
                  <span>{selectedPayment.notes}</span>
                </div>
              )}

              <div className="flex justify-end">
                <Button variant="outline" onClick={() => setViewDialogOpen(false)}>Close</Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </ModuleLayout>
  );
}

