  async postFinanceVoucher(id: string, postedBy: string, overrideReferenceType?: string): Promise<FinanceVoucher | undefined> {
    const voucher = await FinanceVoucherModel.findById(id);
    if (!voucher) return undefined;
    if (voucher.status !== "Draft") {
      throw new Error(`Voucher is already ${voucher.status}. Only Draft vouchers can be posted.`);
    }
    if (voucher.totalDebit !== voucher.totalCredit) {
      throw new Error(`Total debit (${voucher.totalDebit}) must equal total credit (${voucher.totalCredit}).`);
    }
    if (!voucher.entries || voucher.entries.length === 0) {
      throw new Error("Voucher must have at least one entry.");
    }

    const now = new Date().toISOString();
    for (const entry of voucher.entries) {
      const account = await ChartOfAccountsModel.findById(entry.accountId);
      const accountCode = account?.accountCode || "";
      const accountName = entry.accountName || account?.accountName || "";

      const lastEntry = await LedgerEntryModel.findOne({}, { entryNo: 1 }).sort({ entryNo: -1 });
      let nextEntryNum = 1;
      if (lastEntry?.entryNo) {
        const match = lastEntry.entryNo.match(/LE(\d+)/);
        if (match) nextEntryNum = parseInt(match[1], 10) + 1;
      }
      const entryNo = `LE${String(nextEntryNum).padStart(8, "0")}`;

      const existingBalance = await LedgerEntryModel.find({ accountId: entry.accountId })
        .sort({ createdAt: -1 }).limit(1);
      const prevBalance = existingBalance.length > 0 ? existingBalance[0].balance : 0;
      const balance = prevBalance + entry.debit - entry.credit;

      await LedgerEntryModel.create({
        entryNo,
        date: voucher.date,
        accountId: entry.accountId,
        accountCode,
        accountName,
        description: entry.description || voucher.narration,
        referenceType: overrideReferenceType || "Voucher",
        referenceId: voucher._id.toString(),
        referenceNo: voucher.voucherNumber,
        debit: entry.debit,
        credit: entry.credit,
        balance,
        createdBy: postedBy,
        createdAt: now,
      });
    }

    voucher.status = "Posted";
    voucher.postedBy = postedBy;
    voucher.postedAt = now;
    await voucher.save();

    return toDTO<FinanceVoucher>(voucher);
  }

  async cancelFinanceVoucher(id: string, cancelledBy: string): Promise<FinanceVoucher | undefined> {
    const voucher = await FinanceVoucherModel.findById(id);
    if (!voucher) return undefined;
    if (voucher.status !== "Posted") {
      throw new Error(`Only Posted vouchers can be cancelled. Current status: ${voucher.status}`);
    }

    const reversalEntries = voucher.entries.map((e: any) => ({
      accountId: e.accountId,
      accountName: e.accountName,
      debit: e.credit,
      credit: e.debit,
      description: `Reversal: ${e.description || ""}`,
    }));

    const reversalVoucher = await this.createFinanceVoucher({
      type: voucher.type,
      date: new Date().toISOString().split("T")[0],
      entries: reversalEntries,
      totalDebit: voucher.totalCredit,
      totalCredit: voucher.totalDebit,
      narration: `Reversal of ${voucher.voucherNumber}`,
      reference: voucher.voucherNumber,
      status: "Draft",
      createdBy: cancelledBy,
    });

    await this.postFinanceVoucher(reversalVoucher.id, cancelledBy);

    const now = new Date().toISOString();
    voucher.status = "Cancelled";
    voucher.cancelledBy = cancelledBy;
    voucher.cancelledAt = now;
    await voucher.save();

    return toDTO<FinanceVoucher>(voucher);
  }

  async createAutoPostedVoucher(params: {
    type: "Receipt" | "Payment" | "Journal" | "Contra";
    date: string;
    debitAccountCode: string;
    creditAccountCode: string;
    amount: number;
    narration: string;
    reference?: string;
    referenceType: string;
    createdBy: string;
  }): Promise<void> {
    try {
      if (params.reference) {
        const existing = await FinanceVoucherModel.findOne({ reference: params.reference });
        if (existing) {
          console.log(`Auto-voucher skipped: voucher already exists for reference ${params.reference}`);
          return;
        }
      }

      const debitAccount = await ChartOfAccountsModel.findOne({ accountCode: params.debitAccountCode });
      const creditAccount = await ChartOfAccountsModel.findOne({ accountCode: params.creditAccountCode });
      if (!debitAccount || !creditAccount) {
        console.error(`Auto-voucher skipped: accounts not found (${params.debitAccountCode} / ${params.creditAccountCode})`);
        return;
      }

      const entries = [
        {
          accountId: debitAccount._id.toString(),
          accountName: debitAccount.accountName,
          debit: params.amount,
          credit: 0,
          description: params.narration,
        },
        {
          accountId: creditAccount._id.toString(),
          accountName: creditAccount.accountName,
          debit: 0,
          credit: params.amount,
          description: params.narration,
        },
      ];

      const voucher = await this.createFinanceVoucher({
        type: params.type,
        date: params.date,
        entries,
        totalDebit: params.amount,
        totalCredit: params.amount,
        narration: params.narration,
        reference: params.reference,
        status: "Draft",
        createdBy: params.createdBy,
      });

      await this.postFinanceVoucher(voucher.id, params.createdBy, params.referenceType);
    } catch (err) {
      console.error(`Failed to auto-create ${params.referenceType} voucher:`, err);
    }
  }

  async getFinanceDashboard(): Promise<any> {
    const accounts = await ChartOfAccountsModel.find({ isActive: true });
    const accountMap = new Map<string, any>();
    for (const acc of accounts) {
      accountMap.set(acc._id.toString(), {
        accountCode: acc.accountCode,
        accountName: acc.accountName,
        accountType: acc.accountType,
      });
    }

    const ledgerEntries = await LedgerEntryModel.find();
    let totalAssets = 0;
    let totalLiabilities = 0;
    let totalIncome = 0;
    let totalExpenses = 0;

    for (const entry of ledgerEntries) {
      const account = accountMap.get(entry.accountId);
      if (!account) continue;
      const net = entry.debit - entry.credit;
      switch (account.accountType) {
        case "Asset": totalAssets += net; break;
        case "Liability": totalLiabilities += (entry.credit - entry.debit); break;
        case "Income": totalIncome += (entry.credit - entry.debit); break;
        case "Expense": totalExpenses += net; break;
      }
    }

    const recentVouchers = await FinanceVoucherModel.find()
      .sort({ createdAt: -1 }).limit(10);

    const FeeVoucherModel = (await import("./models/FeeVoucher")).default;
    const PayrollModel = (await import("./models/Payroll")).default;
    const { Payment: PaymentModel } = await import("./models/Payment");

    const totalFeeCollected = await PaymentModel.aggregate([
      { $match: { type: "Payment", status: "Completed" } },
      { $group: { _id: null, total: { $sum: "$amount" } } },
    ]);

    const totalPayrollPaid = await PayrollModel.aggregate([
      { $match: { status: "Paid" } },
      { $group: { _id: null, total: { $sum: "$netSalary" } } },
    ]);

    const recentFeePayments = await PaymentModel.find({ type: "Payment", status: "Completed" })
      .sort({ createdAt: -1 }).limit(5);

    const recentPayrollPayments = await PayrollModel.find({ status: "Paid" })
      .sort({ updatedAt: -1 }).limit(5);

    return {
      totalAssets,
      totalLiabilities,
      totalIncome,
      totalExpenses,
      recentVouchers: toDTOArray<FinanceVoucher>(recentVouchers),
      totalFeeCollected: totalFeeCollected[0]?.total || 0,
      totalPayrollPaid: totalPayrollPaid[0]?.total || 0,
      recentFeePayments: recentFeePayments.map((p: any) => ({
        id: p._id.toString(),
        receiptNo: p.receiptNo,
        studentName: p.studentName,
        amount: p.amount,
        paymentMode: p.paymentMode,
        paymentDate: p.paymentDate,
      })),
      recentPayrollPayments: recentPayrollPayments.map((p: any) => ({
        id: p._id.toString(),
        payrollId: p.payrollId,
        staffName: p.staffName,
        netSalary: p.netSalary,
        month: p.month,
        paidDate: p.paidDate,
      })),
    };
  }

  async getTimetables(): Promise<Timetable[]> {
    const docs = await TimetableModel.find().sort({ createdAt: -1 });
    return toDTOArray<Timetable>(docs);
  }

  async getTimetable(id: string): Promise<Timetable | undefined> {
    const doc = await TimetableModel.findById(id);
    return doc ? toDTO<Timetable>(doc) : undefined;
  }

  async createTimetable(timetable: InsertTimetable): Promise<Timetable> {
    // Check if a timetable already exists for this class-section
    const existing = await TimetableModel.findOne({
      class: timetable.class,
      section: timetable.section
    });

    if (existing) {
      // Merge new slots with existing slots
      // Remove duplicate slots (same day + period) and add new ones
      const existingSlots = existing.slots || [];
      const newSlots = timetable.slots || [];

      // Create a map of existing slots by day-period key
      const slotMap = new Map();
      existingSlots.forEach((slot: any) => {
        const key = `${slot.day}-${slot.period}`;
        slotMap.set(key, slot);
      });

      // Add or update with new slots
      newSlots.forEach((slot: any) => {
        const key = `${slot.day}-${slot.period}`;
        slotMap.set(key, slot);
      });

      // Convert map back to array
      existing.slots = Array.from(slotMap.values());
      existing.updatedAt = timetable.updatedAt;

      await existing.save();
      return toDTO<Timetable>(existing);
    } else {
      // Create new timetable
      const doc = await TimetableModel.create(timetable);
      return toDTO<Timetable>(doc);
    }
  }

  async updateTimetable(id: string, updates: Partial<Timetable>): Promise<Timetable | undefined> {
    const doc = await TimetableModel.findByIdAndUpdate(id, updates, { new: true });
    return doc ? toDTO<Timetable>(doc) : undefined;
  }

